  ('fire-eq-tech-moex-03407', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '消防緊急供電電源，依設置規定，下列何者規範項目有誤？', '["裝設發電機及蓄電池之處所為防火構造", "緊急電源裝置切換開關，於常用電源切斷時自動切換供應電源至緊急電源供應", "發電機裝設適當開關或連鎖機件，以防止向正常供電線路逆向電力", "電源回路之配線，應設專用回路，施予耐熱保護"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "36c05ea3a5ff", "answer_pdf_sha1": "439a300e3c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03408', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '無線電通信輔助設備使用洩波同軸電纜，在任一出入口與其他出入口之步行距離大於 300 公尺時，設置 2 個以上，依設置規定，下列何者有誤？', '["洩波同軸電纜之標稱阻抗為50歐姆", "洩波同軸電纜經耐熱處理", "設於距樓地板面或基地地面高度0.8公尺至1.5公尺間", "該電纜適合傳送或輻射150百萬赫（Mhz），保護箱內設長度2公尺以上之射頻電纜"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "36c05ea3a5ff", "answer_pdf_sha1": "439a300e3c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03409', 'fire-eq-tech', 'fire-eq-tech-moex-097-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '避難器具固定架或支固器具使用螺栓固定時，依規定使用錨定螺栓，測定扭力公式，T=KDN；若螺栓直徑 D=3cm，設計拉拔荷重N=200kgf，K為係數，其轉矩值（kgf-cm）應為', '["144", "288", "200", "600"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "36c05ea3a5ff", "answer_pdf_sha1": "439a300e3c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
